"""HLD Key Technologies: Redis, Elasticsearch, Kafka — 20 deep MCQs each."""
from __future__ import annotations
from .lld_practice import quiz, Lesson

def redis_lesson() -> Lesson:
    return Lesson(id="hld-redis", number=116, title="Redis",
        focus=("data structures","persistence","clustering","pub/sub","Lua scripts","eviction"),
        overview="Redis is the Swiss-army knife of system design. Know its data structures, persistence, and clustering internals.",
        patterns=(), badge="HLD Tech", tasks=(
        quiz("redis-1","What is Redis' threading model?","hard",("redis",),("Single-threaded event loop for commands; avoids locking overhead. I/O threads added in 6.0","A transport layer optimization that reduces round-trip overhead using multiplexing","A partitioning algorithm that assigns data based on a hash of the geographic region","A consensus protocol that uses a rotating leader to distribute write coordination load"),0,"Single-threaded means no locks, no context switches. In-memory ops are so fast one thread saturates network."),
        quiz("redis-2","What are the main Redis data structures?","medium",("redis",),("Strings, Hashes, Lists, Sets, Sorted Sets, Streams, HyperLogLog, Bitmaps","A query optimization strategy that rewrites subqueries into more efficient join patterns","A consistency model where reads from any replica are guaranteed to be monotonically fresh","A transaction isolation level that prevents phantom reads using predicate locking"),0,"Each structure has specialized commands and use cases. Sorted Sets for leaderboards, Streams for event logs."),
        quiz("redis-3","What is a Redis Sorted Set and when would you use it?","hard",("redis",),("A set where each member has a score, supporting O(log n) ranked queries — ideal for leaderboards","An index maintenance operation that rebuilds fragmented pages for better scan performance","A data structure that stores cache metadata compactly using probabilistic counting","A monitoring tool that tracks hit rates, eviction counts, and memory usage per cache pool"),0,"ZADD/ZRANGE/ZRANK: perfect for leaderboards, priority queues, time-windowed aggregations."),
        quiz("redis-4","What is the difference between RDB and AOF persistence?","hard",("redis",),("RDB: periodic point-in-time snapshots. AOF: append-every-write log. RDB is compact; AOF is more durable","A persistence mechanism that snapshots the cache state to disk for crash recovery","A state synchronization approach that reconciles differences using Merkle tree comparison","A process that periodically reconciles state between systems to detect and fix drift"),0,"Best practice: use both. AOF for durability (fsync every second). RDB for fast restarts."),
        quiz("redis-5","How does Redis Cluster shard data?","hard",("redis",),("16384 hash slots distributed across master nodes; each key maps to CRC16(key) mod 16384","A schema design pattern that embeds frequently accessed data to avoid join overhead","A clock synchronization technique that uses NTP with bounded drift for ordering events","A communication pattern where services exchange messages through a centralized broker"),0,"Clients compute the slot and connect directly to the owning node. MOVED/ASK redirects handle migrations."),
        quiz("redis-6","What is Redis pub/sub and its limitation?","medium",("redis",),("Fire-and-forget messaging; messages are lost if no subscriber is listening at the time","A deployment strategy that gradually shifts traffic from the old version to the new one","A technique that partitions workload across worker pools based on resource requirements","A flow control mechanism that prevents the sender from overwhelming the receiver"),0,"Pub/sub doesn't persist. For durability, use Redis Streams (XADD/XREAD with consumer groups)."),
        quiz("redis-7","What is Redis Streams vs pub/sub?","hard",("redis",),("Streams persist messages, support consumer groups with acknowledgment; pub/sub is fire-and-forget","A load shedding strategy that drops low-priority requests when resource utilization is high","A monitoring approach that aggregates metrics from multiple sources into unified dashboards","A routing strategy that directs traffic based on geographic proximity of the client"),0,"Streams (XADD/XREAD/XACK) provide Kafka-like semantics within Redis."),
        quiz("redis-8","What is the Redis eviction policy LRU vs LFU?","hard",("redis",),("volatile-lru: evict least recently used keys with TTL. allkeys-lfu: evict least frequently used from all keys","A data pipeline stage that transforms and enriches events before writing to storage","A congestion avoidance algorithm that dynamically adjusts the transmission window","A replication technique that synchronously mirrors writes to a standby for zero data loss"),0,"Choose based on access pattern. LFU is better for skewed workloads where some keys are always hot."),
        quiz("redis-9","What is Redis Sentinel?","hard",("redis",),("Provides high availability with automatic failover: monitors masters, detects failure, promotes replicas","A protocol that batches multiple requests into a single TCP segment for efficiency","A connection management approach that pins clients to specific backend instances","An eviction algorithm that considers both recency and frequency when selecting victims"),0,"Sentinel: quorum-based failure detection → automatic promotion → client notification of new master."),
        quiz("redis-10","What is the Redis MULTI/EXEC transaction?","hard",("redis",),("Queues commands and executes atomically — but no rollback on individual command failure","A resilience pattern that isolates failures in one subsystem from propagating to others","A failure detection mechanism using heartbeat intervals and configurable timeout thresholds","A cache coherence protocol that broadcasts invalidation messages to all cache tiers"),0,"MULTI/EXEC: all-or-nothing execution. WATCH enables optimistic locking (CAS pattern)."),
        quiz("redis-11","What is Redis Lua scripting?","hard",("redis",),("Execute Lua scripts atomically on the server — enables complex operations without round trips","A pattern where incoming requests are buffered and processed in priority-ordered batches","A backup mechanism that captures incremental changes since the last full snapshot","A technique where the server pre-fetches resources based on predicted client needs"),0,"EVAL: server-side atomic execution. Useful for rate limiting, token bucket, and complex CAS operations."),
        quiz("redis-12","What is the Redis HyperLogLog?","hard",("redis",),("A probabilistic data structure for cardinality estimation (count unique items) with O(1) space","A sharding approach that distributes cached entries across nodes by consistent hashing","A monitoring tool that tracks query execution plans and identifies slow running queries","A connection management approach that limits concurrent sessions to prevent overload"),0,"PFADD/PFCOUNT: count unique visitors with only 12KB memory, ~0.81% standard error."),
        quiz("redis-13","How does Redis replication work?","hard",("redis",),("Async replication from master to replicas. Initial full sync (RDB dump) then incremental command stream","A warming strategy that pre-loads data based on access frequency from the previous day","A serialization format that reduces cache entry size through schema-aware compression","A prefetching algorithm that predicts future access patterns from recent query history"),0,"Async replication means replicas may lag. For strong consistency, use WAIT command."),
        quiz("redis-14","What is Redis pipelining?","medium",("redis",),("Sending multiple commands without waiting for replies, then reading all replies — reduces round-trip overhead","A load balancing technique using configurable thresholds","A storage engine optimization that pre-sorts data on disk for sequential access patterns","A DNS-based technique that distributes queries across multiple authoritative servers"),0,"Pipelining: send 1000 commands → get 1000 replies in one round trip. 10x throughput improvement."),
        quiz("redis-15","What is the Redis Bitmap data structure?","hard",("redis",),("A compact bit array supporting SETBIT/GETBIT/BITCOUNT — perfect for tracking binary states per user","A coordination service that uses ephemeral nodes for automatic failure detection","A replication strategy where writes go to any node and conflicts are resolved on read","A replication technique that mirrors hot cache entries across multiple nodes for availability"),0,"Bitmap: track 1B users' daily login with only 125MB. BITCOUNT for analytics. BITOP for set operations."),
        quiz("redis-16","What are the risks of using Redis as a primary database?","hard",("redis",),("Data loss if persistence isn't configured properly; limited by RAM size; no complex queries/JOINs","A partitioning strategy that splits data based on a hash of the composite primary key","A testing approach that injects controlled failures to verify system recovery behavior","A membership protocol where nodes periodically exchange state with random cluster peers"),0,"Redis works as a primary DB for specific use cases (sessions, caches) but not for general transactional data."),
        quiz("redis-17","What is Redis Cluster's split-brain handling?","hard",("redis",),("Minority partition nodes stop accepting writes after a timeout; clients reconnect to majority partition","A scheduling algorithm that assigns tasks to workers based on estimated completion time","A mechanism that compresses HTTP headers to reduce bandwidth on repeated requests","A security protocol that authenticates both client and server during the handshake"),0,"cluster-node-timeout: nodes in minority partition become read-only. Prevents conflicting writes."),
        quiz("redis-18","How do you implement a distributed lock with Redis?","hard",("redis",),("SET key value NX PX milliseconds (atomic acquire with TTL); DEL to release. Redlock for multi-node","Using a standard SETNX command and deleting the key without checking value ownership","Running MULTI and EXEC commands sequentially to block other client connections","Executing INCR and DECR commands on a counter key to track lock acquisition counts"),0,"SET NX PX: atomic acquire. TTL prevents deadlocks. Check lock value before releasing to prevent stale releases."),
        quiz("redis-19","What is Redis Cluster resharding?","hard",("redis",),("Moving hash slots between nodes online — MIGRATE command moves keys slot by slot while serving traffic","Provisioning a brand new cluster instance and copying the database files offline","Executing a FLUSHALL command to delete old keys before distributing new keys","Restarting all cluster nodes simultaneously to re-read the configuration file"),0,"redis-cli --cluster reshard: moves slots live. ASK redirects handle in-flight migrations."),
        quiz("redis-20","What is the memory overhead per key in Redis?","hard",("redis",),("~50-70 bytes per key for internal structures (dict entry, SDS string, expiry) regardless of value size","Exactly 0 bytes since keys are stored as raw unpadded memory pointers","Approximately 1 KB per key to accommodate hash collisions and metadata","Exactly 1 byte per key to store the key's length prefix"),0,"With 1B small keys, overhead alone = ~50-70GB. Use hash packing for small values to reduce overhead."),
    ))

def elasticsearch_lesson() -> Lesson:
    return Lesson(id="hld-elasticsearch", number=117, title="Elasticsearch",
        focus=("inverted index","sharding","relevance scoring","aggregations","ELK stack","mapping"),
        overview="Elasticsearch powers search, analytics, and logging. Know its internals and query capabilities.",
        patterns=(), badge="HLD Tech", tasks=(
        quiz("es-1","What is Elasticsearch optimized for?","medium",("elasticsearch",),("Full-text search, analytics, and log aggregation using inverted indexes","Recursive graph traversal and relationship mapping across multiple tables","Storing high-volume time-series metric data exclusively without indexing","Executing complex ACID transactions with distributed table locking"),0,"ES uses inverted indexes for fast text search. Great for log analytics (ELK) and fuzzy matching."),
        quiz("es-2","What is an inverted index?","hard",("elasticsearch",),("A data structure mapping each unique term to the list of documents containing it","A key-value hash table that uses linear probing to resolve collision buckets","A self-balancing B-tree index where leaf nodes point to table records","A sorted array of document IDs that is binary searched on every query"),0,"Inverted index: term → [doc1, doc5, doc42]. O(1) lookup of which documents contain a search term."),
        quiz("es-3","How does Elasticsearch shard data?","hard",("elasticsearch",),("Each index is split into primary shards distributed across nodes; each shard is a self-contained Lucene index","By sorting indices chronologically and mapping them to daily partitions","By storing all indices on a single node and executing multi-threading","Elasticsearch does not support sharding, only replication across nodes"),0,"Default: 1 primary shard per index. Shards enable horizontal scaling. Replica shards add fault tolerance."),
        quiz("es-4","What is the difference between a primary and replica shard?","medium",("elasticsearch",),("Primary handles writes; replicas serve reads and provide failover if primary fails","Replica shards process all database write queries synchronously","There is no difference; they are duplicate terms for standby nodes","Primary shards are inactive backups that only wake up on network failure"),0,"Replicas: read scaling + fault tolerance. A replica can be promoted to primary on node failure."),
        quiz("es-5","What is TF-IDF in Elasticsearch?","hard",("elasticsearch",),("Term Frequency × Inverse Document Frequency — a relevance scoring formula for full-text search","A specialized database index that stores document structures hierarchically","A sharding strategy that partitions documents based on their term frequency","A cache eviction policy that prioritizes frequently accessed search terms"),0,"TF-IDF: rare terms matching a document score higher. ES now uses BM25 (improved TF-IDF) by default."),
        quiz("es-6","What is BM25?","hard",("elasticsearch",),("Okapi BM25: the default relevance scoring algorithm in ES — improves on TF-IDF with term frequency saturation","A database version metadata field used for schema migration tracking","A cache eviction algorithm that removes keys based on search query lengths","A partitioning strategy that splits data across nodes based on term counts"),0,"BM25 prevents very high term frequencies from dominating scores. Better than raw TF-IDF."),
        quiz("es-7","What is the ELK stack?","medium",("elasticsearch",),("Elasticsearch (search/analytics) + Logstash (ingestion) + Kibana (visualization)","An in-memory cache layer placed in front of primary databases","A NoSQL document database cluster optimized for transactional writes","A global CDN caching layer that handles static file distributions"),0,"ELK: the go-to for log aggregation, monitoring, and observability."),
        quiz("es-8","What is a mapping in Elasticsearch?","medium",("elasticsearch",),("Schema definition: specifies field types (text, keyword, integer, date) and how they're indexed","A configuration file containing list of nodes in the Elasticsearch cluster","A routing table that maps client requests to specific partition nodes","A geographic database index optimized for storing latitude and longitude"),0,"Mapping controls tokenization (text vs keyword), indexing options, and stored fields."),
        quiz("es-9","What is the difference between text and keyword field types?","hard",("elasticsearch",),("Text is analyzed (tokenized, lowercased) for full-text search; keyword is exact match (no tokenization)","Text fields are significantly faster to query than keyword fields","Keyword fields support fuzzy matching and character tokenization natively","They are synonyms for the same string storage format in Lucene"),0,"Use text for searchable content. Use keyword for exact matches, sorting, and aggregations."),
        quiz("es-10","What is an analyzer in Elasticsearch?","hard",("elasticsearch",),("A pipeline of character filters, tokenizer, and token filters that processes text for indexing/search","A shard partitioning strategy configured during cluster setup","A primary data type used to define numeric values in mapping rules","A system monitoring daemon that tracks search query execution latency"),0,"Standard analyzer: lowercase + tokenize. Custom analyzers handle stemming, synonyms, stopwords."),
        quiz("es-11","How does Elasticsearch handle near-real-time search?","hard",("elasticsearch",),("Documents are searchable after a refresh interval (~1 second) when in-memory buffer is written to a segment","By returning search results instantly from memory prior to disk commit","By requiring all write transactions to commit to disk before they can be read","By indexing documents directly into the primary shard without caching"),0,"Refresh creates a new searchable segment from the in-memory buffer. Default interval: 1 second."),
        quiz("es-12","What is a segment in Elasticsearch?","hard",("elasticsearch",),("An immutable Lucene index file; new documents create new segments, which are periodically merged","A relational database table containing raw document field details","A subset of a shard that stores replica configurations","A replication node that acts as a standby coordinator"),0,"Segments are immutable. Deletes create tombstones. Merging compacts segments and removes tombstones."),
        quiz("es-13","What are aggregations in Elasticsearch?","medium",("elasticsearch",),("Analytics operations: bucket (group by), metric (avg, sum), and pipeline aggregations on search results","An in-memory cache coherence feature that buffers index changes","A database replication mode that mirrors indexes across geographic zones","Distributed SQL JOIN queries executed across multiple distinct indexes"),0,"Aggregations enable dashboard analytics: top terms, date histograms, percentiles, nested buckets."),
        quiz("es-14","What is the document routing in Elasticsearch?","hard",("elasticsearch",),("By default, shard = hash(document_id) % num_primary_shards. Custom routing co-locates related docs","A load balancing rule that routes client traffic round-robin","A DNS server resolution mechanism that selects the closest cluster node","A CDN configuration that routes document search requests to edge caches"),0,"Custom routing: all docs for a tenant go to the same shard, enabling efficient single-shard queries."),
        quiz("es-15","What is the difference between Elasticsearch and a relational database?","medium",("elasticsearch",),("ES: denormalized, search-optimized, eventually consistent. RDBMS: normalized, transactional, strongly consistent","ES is a database replacement across multiple service instances","They are identical search-optimized databases with different query languages","RDBMS supports full-text search for improved throughput"),0,"ES is NOT a primary database. It's a search engine used as a read-optimized projection."),
        quiz("es-16","What is the scroll API in Elasticsearch?","hard",("elasticsearch",),("Efficiently retrieves large result sets by keeping a point-in-time snapshot, avoiding deep pagination costs","A standard pagination offset parameter used in search endpoints","A cache optimization setting that keeps hot documents in memory","An append-only write API optimized for bulk document indexing"),0,"Scroll: for batch processing. Search_after: for live pagination. Both avoid the deep-pagination O(n) problem."),
        quiz("es-17","How does Elasticsearch handle updates?","hard",("elasticsearch",),("Documents are immutable; an update creates a new version and marks the old one as deleted","By executing direct modification of the Lucene index files on disk","By performing in-place updates to the specific document fields","By running a standard SQL UPDATE command on the underlying database"),0,"Lucene segments are immutable. Updates = delete old + index new. Merging reclaims deleted space."),
        quiz("es-18","What is cross-cluster replication in Elasticsearch?","hard",("elasticsearch",),("Replicating indices across geographically separate clusters for disaster recovery and local reads","Replicating indices across different nodes within a single cluster","A specialized node type configured to handle heavy write traffic","A primary shard feature that mirrors data to replica shards"),0,"CCR: leader cluster → follower cluster. Follower serves local reads. Failover if leader goes down."),
        quiz("es-19","What is the percolate query?","hard",("elasticsearch",),("Reverse search: store queries, then match new documents against stored queries (alerting, notifications)","A metric aggregation that counts unique search queries","A query filter that restricts search results to a specific timeframe","A standard search query that looks up matching text documents"),0,"Percolate: 'which of my saved searches match this new document?' Used for alerts and saved searches."),
        quiz("es-20","How do you handle Elasticsearch at scale?","hard",("elasticsearch",),("Shard per tenant/time, hot-warm-cold architecture, index lifecycle management, and force-merge old indices","Scaling up a single master server node with high-capacity CPUs","Relying on Elasticsearch auto-scaling without index organization","Upgrading the memory allocation of all nodes without partitioning indices"),0,"ILM: hot (SSD, recent) → warm (HDD, older) → cold (frozen, archive). Auto-manages index lifecycle."),
      ))

def kafka_lesson() -> Lesson:
    return Lesson(id="hld-kafka", number=118, title="Kafka",
        focus=("partitions","consumer groups","offsets","replication","exactly-once","Kafka Streams"),
        overview="Kafka is the backbone of event-driven architecture. Know partitions, consumer groups, and delivery guarantees.",
        patterns=(), badge="HLD Tech", tasks=(
        quiz("kafka-1","What makes Kafka different from a traditional queue?","hard",("kafka",),("Kafka is a distributed commit log: retains messages, allows replay, and supports multiple consumer groups","Kafka is a simpler message queue with no partition scaling capabilities","Kafka is an in-memory key-value database optimized for real-time reads","Kafka does not preserve message order within any topic boundaries"),0,"Unlike RabbitMQ, Kafka retains messages after consumption. Consumers track their offset."),
        quiz("kafka-2","What is a Kafka partition?","hard",("kafka",),("The unit of parallelism — messages are ordered within a partition, distributed across brokers","A logical consumer group that reads from multiple partition instances","A physical database shard configured on the storage disk block","A topic namespace prefix used to categorize message streams"),0,"Partitions enable horizontal scaling. Ordering guaranteed only within a partition."),
        quiz("kafka-3","What is a consumer group?","medium",("kafka",),("A set of consumers sharing partition ownership — each partition consumed by exactly one member","A logical grouping of related topics that share a consumer offset","A cluster pool of message broker nodes coordinating partition writes","A data replication mechanism that mirrors partitions across brokers"),0,"10 partitions → max 10 consumers in a group. Adding more consumers than partitions wastes them."),
        quiz("kafka-4","What happens when a consumer falls behind?","hard",("kafka",),("Consumer lag increases; it catches up by reading from disk (retention period protects messages)","The topic is automatically paused until the consumer catches up","All unconsumed messages are deleted from the broker to free memory","Kafka blocks all incoming producer writes to prevent partition growth"),0,"Monitor consumer lag. If consumer can't keep up, add more consumers (up to partition count)."),
        quiz("kafka-5","What is Kafka's replication model?","hard",("kafka",),("Each partition has a leader and N-1 follower replicas. Writes go to leader; followers replicate asynchronously","A peer-to-peer architecture where nodes sync without coordination","Kafka does not replicate partition data, relying on disk backups instead","A multi-leader model where writes can be sent to any replica node"),0,"ISR (In-Sync Replicas): only replicas that are caught up. Leader election from ISR on failure."),
        quiz("kafka-6","What is the ISR (In-Sync Replica) set?","hard",("kafka",),("The subset of replicas that are fully caught up with the leader — only ISR members can be elected leader","A system performance metric that tracks partition latency spikes","The total set of all replicas configured for a given topic partition","A consumer group configured to read messages in a transactional block"),0,"min.insync.replicas: minimum ISR size required for acks=all. Prevents data loss on leader failure."),
        quiz("kafka-7","What is acks=all in Kafka?","hard",("kafka",),("Producer waits for all ISR replicas to acknowledge the write before considering it successful","The producer waits for the leader replica alone to acknowledge the write","The producer requires confirmation from at least one broker in each datacenter","No acknowledgment is requested; writes are fire-and-forget for speed"),0,"acks=all: highest durability. acks=1: leader only (risk of loss). acks=0: fire-and-forget (fastest)."),
        quiz("kafka-8","How does Kafka achieve high throughput?","hard",("kafka",),("Sequential I/O (append-only), batching, compression, zero-copy transfer, and OS page cache","Restricting the topic to a single partition to maximize disk throughput","Executing random disk write operations to bypass system page caches","Storing all message logs in-memory without persistent disk writes"),0,"Kafka writes sequentially to disk (faster than random SSD). Zero-copy: sendfile() syscall."),
        quiz("kafka-9","What is Kafka Connect?","medium",("kafka",),("Framework for streaming data between Kafka and external systems via source/sink connectors","A client application library used to write custom stream consumers","A cluster monitoring utility that tracks consumer lag metrics","A security credentials controller that authorizes API requests"),0,"Source connectors ingest (DB→Kafka). Sink connectors export (Kafka→ES/S3). No custom code needed."),
        quiz("kafka-10","What is Kafka Streams?","hard",("kafka",),("A client library for building stream processing applications that transform Kafka topics","A system monitoring dashboard that tracks partition throughput","A binary message serialization format similar to Apache Avro","A broker-side router that dynamically distributes message packets"),0,"Kafka Streams: stateful processing, windowing, joins — runs as a regular Java app, no separate cluster."),
        quiz("kafka-11","What is exactly-once semantics (EOS) in Kafka?","hard",("kafka",),("Idempotent producer + transactional writes + consumer read-committed = end-to-end exactly-once within Kafka","Consumer-side deduplication guarantees without producer-side changes","An architectural constraint that is mathematically impossible to achieve","At-least-once message delivery configured with automatic retries"),0,"EOS: producer deduplication (idempotent) + atomic multi-partition writes (transactions) + consumer isolation."),
        quiz("kafka-12","What is a Kafka topic compaction?","hard",("kafka",),("Log compaction retains only the latest value for each key, discarding older versions — like a changelog","A partition partitioning rule configured during topic creation","A data compression algorithm applied to message payload files","Deleting all messages from a topic once they reach a set age threshold"),0,"Compacted topics: keep latest state per key. Used for CDC, configuration, and state snapshots."),
        quiz("kafka-13","How does Kafka handle ordering across partitions?","hard",("kafka",),("It doesn't — ordering is only within a partition. Use a single partition for strict global order (limits throughput)","Enforcing strict global ordering using distributed epoch timestamps","Sorting messages dynamically by sorting payload timestamps in memory","Automatically reordering messages at the consumer group level on arrival"),0,"Design your partition key so related messages go to the same partition for ordering."),
        quiz("kafka-14","What is consumer rebalancing?","hard",("kafka",),("When consumers join/leave a group, partitions are reassigned. Causes a brief processing pause","Resetting all partition offsets to the earliest available message","Restarting broker nodes to reassign partition leadership roles","Migrating partition log directories between physical broker disks"),0,"Rebalancing can cause duplicates (at-least-once). Cooperative rebalancing (incremental) reduces impact."),
        quiz("kafka-15","What is the Schema Registry?","hard",("kafka",),("A service storing Avro/Protobuf/JSON schemas for Kafka messages, enabling schema evolution and validation","A cluster monitoring console that checks broker health metrics","A broker-side metadata store that routes message payloads to clients","A relational database configuration used to persist partition offsets"),0,"Schema Registry ensures producers and consumers agree on message format. Supports backward/forward compatibility."),
        quiz("kafka-16","What is a dead letter topic?","medium",("kafka",),("A topic where messages that fail processing are sent for later investigation and reprocessing","A topic that has been marked for deletion by the system administrator","A replication backup folder that stores mirrored partition logs","An operating system error log file that records consumer exceptions"),0,"DLT: poison messages go here after max retries. Prevents blocking the main consumer."),
        quiz("kafka-17","What is the difference between Kafka's retention by time vs size?","medium",("kafka",),("Time-based: delete messages older than N days. Size-based: delete oldest when topic exceeds N GB","Retention settings are ignored; messages are always kept indefinitely","They are synonyms for the same log segment deletion mechanism","Topic sizes are hard-coded; retention is managed solely by time limits"),0,"Configure per topic. Time-based for event streams. Size-based for resource-constrained environments."),
        quiz("kafka-18","What is MirrorMaker 2?","hard",("kafka",),("Kafka's built-in cross-cluster replication tool for disaster recovery and multi-datacenter setups","A schema validation tool that ensures compatibility across topic partitions","A monitoring daemon that tracks consumer lag in real-time","A client consumer library used to read messages from multiple topics"),0,"MM2: replicate topics between clusters. Supports active-active and active-passive topologies."),
        quiz("kafka-19","How do you choose the number of partitions for a topic?","hard",("kafka",),("Based on target throughput: partitions ≥ max(producer throughput / partition throughput, consumer count)","A fixed value of 100 partitions per topic is required by the broker","A single partition should always be chosen to optimize write scaling","Partition counts are determined by the average message payload size"),0,"More partitions = more parallelism but also more overhead (file handles, memory, rebalancing time)."),
        quiz("kafka-20","What is the Kafka transaction protocol?","hard",("kafka",),("Atomic writes across multiple partitions: all messages in a transaction are committed or aborted together","A locking mechanism that prevents consumers from reading uncommitted topics","A database transaction wrapper that acts similarly to standard SQL commits","A replication protocol that handles failover elections among ISR members"),0,"Transactions enable exactly-once: produce to multiple topics/partitions atomically. Used with Kafka Streams."),
    ))
